/** Every board word must be 3–8 letters, A–Z; the loader filters the rest. */
const WORD_RE = /^[A-Z]{3,8}$/;

function buildDictionary(): { words: Set<string>; prefixes: Set<string> } {
  const words = new Set<string>();
  const prefixes = new Set<string>();
  for (const token of RAW.split(/\s+/)) {
    const w = token.trim().toUpperCase();
    if (!WORD_RE.test(w)) continue;
    // reject any Q not immediately followed by U — the board only ever
    // produces Q via the "QU" tile, so such words could never be spelled
    if (/Q(?!U)/.test(w)) continue;
    if (words.has(w)) continue;
    words.add(w);
    for (let i = 1; i <= w.length; i++) prefixes.add(w.slice(0, i));
  }
  return { words, prefixes };
}

const DICT = buildDictionary();

export const HUNT_WORDS: ReadonlySet<string> = DICT.words;
export const HUNT_PREFIXES: ReadonlySet<string> = DICT.prefixes;

export function isHuntWord(w: string): boolean {
  return DICT.words.has(w);
}

/** True when `s` begins some dictionary word (used to prune drag/solver paths). */
export function isHuntPrefix(s: string): boolean {
  return DICT.prefixes.has(s);
}

/**
 * Integrity check for the bank (run by `npm run validate`). Returns a list of
 * problems; an empty array means the dictionary is sound.
 */
export function validateHuntDictionary(): string[] {
  const errors: string[] = [];
  const { words, prefixes } = DICT;

  if (words.size < 1500) {
    errors.push(`only ${words.size} words — need at least 1500`);
  }

  let short = 0;
  for (const w of words) {
    if (!WORD_RE.test(w)) errors.push(`"${w}" is not 3–8 uppercase letters`);
    if (/Q(?!U)/.test(w)) errors.push(`"${w}" has a Q not followed by U`);
    if (w.length === 3) short++;
    // every prefix of every word must be present in the prefix set
    for (let i = 1; i <= w.length; i++) {
      if (!prefixes.has(w.slice(0, i))) {
        errors.push(`prefix "${w.slice(0, i)}" of "${w}" missing from prefix set`);
        break;
      }
    }
    if (errors.length > 40) break; // stop spamming once clearly broken
  }

  // easy/medium boards lean on 3-letter words — keep the bank dense there
  if (short < 150) errors.push(`only ${short} three-letter words — need at least 150 for fair easy boards`);

  return errors;
}

/** Small stats accessor for the validation report. */
export function huntDictStats(): { total: number; byLen: Record<number, number> } {
  const byLen: Record<number, number> = {};
  for (const w of DICT.words) byLen[w.length] = (byLen[w.length] ?? 0) + 1;
  return { total: DICT.words.size, byLen };
}
